function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const row = $json;

return {
  json: {
    vorgangKey: safeStr(row.vorgangKey),
    vorgangsnummer: safeStr(row.vorgangsnummer),
    sourceTopic: safeStr(row.sourceTopic),
    sourceConflict: safeStr(row.sourceConflict),
    requiredTerms: asArr(row.requiredTerms),
    requiredObjects: asArr(row.requiredObjects),
    requiredAction: safeStr(row.requiredAction),
    affectedGroups: asArr(row.affectedGroups),
    concreteNumbers: asArr(row.concreteNumbers),
    responsibilities: asArr(row.responsibilities),
    documentType: safeStr(row.documentType),
    quotesVerbatim: asArr(row.quotesVerbatim),
    sprengstoff: safeStr(row.sprengstoff) || 'GERING'
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

function getAiText(j) {
  if (typeof j.content === 'string') return j.content;
  if (typeof j.text === 'string') return j.text;
  if (j.message && typeof j.message.content === 'string') return j.message.content;
  if (Array.isArray(j.choices) && j.choices[0] && j.choices[0].message) return safeStr(j.choices[0].message.content);
  if (Array.isArray(j.output)) {
    const msg = j.output.find(function(o) { return o && o.type === 'message' && Array.isArray(o.content); });
    const part = msg && msg.content.find(function(c) { return c && typeof c.text === 'string'; });
    if (part) return part.text;
  }
  return safeStr(JSON.stringify(j));
}

function extractJson(text) {
  const t = safeStr(text).replace(/```json/gi, '```').replace(/```/g, '');
  const start = t.indexOf('{');
  const end = t.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return null;
  try { return JSON.parse(t.substring(start, end + 1)); } catch (e) { return null; }
}

function normalizeText(v) {
  return safeStr(v).toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
}
function stemLight(w) {
  return w.replace(/(ungen|ierung|heit|keit|schaft|tion|ieren|iere|iert|ung|lich|isch|ische|ischen|ischer|isches)$/, '').replace(/(en|er|em|es|e|n|s|t)$/, '');
}
function tokenOverlap(a, b) {
  const tokensA = normalizeText(a).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  const tokensB = normalizeText(b).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  if (tokensA.some(w => tokensB.includes(w))) return true;
  const rawA = normalizeText(a).replace(/[\W_]+/g, ''), rawB = normalizeText(b).replace(/[\W_]+/g, '');
  for (const tok of tokensA) { if (tok.length >= 5 && rawB.includes(tok)) return true; }
  for (const tok of tokensB) { if (tok.length >= 5 && rawA.includes(tok)) return true; }
  return false;
}

const base = $('Normalisiere Eingabe').item.json;
const kbNode = $('Waehle Kernbotschaft').item.json;
const fixedKernbotschaft = safeStr(kbNode.kernbotschaft);
const aiText = getAiText($json);
const parsed = extractJson(aiText);

const ceilings = { KEINER: 2, GERING: 2, MITTEL: 4, HOCH: 5 };
const maxIntensity = ceilings[base.sprengstoff] || 2;
const requiredTerms = asArr(base.requiredTerms);

function clampVariant(v, idx) {
  v = (v && typeof v === 'object') ? v : {};
  let intensity = Number(v.satireIntensity);
  if (!Number.isFinite(intensity)) intensity = 1;
  intensity = Math.max(1, Math.min(maxIntensity, Math.round(intensity)));
  const imageHeadline = safeStr(v.imageHeadline);
  const imageSubline = safeStr(v.imageSubline);
  const headlineText = imageHeadline + ' ' + imageSubline;
  const headlineGrounded = requiredTerms.length === 0 ? null : requiredTerms.some(function(t) { return tokenOverlap(t, headlineText); });
  return {
    code: safeStr(v.code) || ('S' + (idx + 1)),
    satireIntensity: intensity,
    satireTarget: safeStr(v.satireTarget),
    satireBrief: safeStr(v.satireBrief),
    satireAngle: safeStr(v.satireAngle),
    satirePunchlines: asArr(v.satirePunchlines),
    satireDoNotClaim: asArr(v.satireDoNotClaim),
    satireSafetyNote: safeStr(v.satireSafetyNote),
    imageHeadline: imageHeadline,
    imageSubline: imageSubline,
    headlineGrounded: headlineGrounded
  };
}

if (!parsed || !Array.isArray(parsed.variants) || parsed.variants.length === 0) {
  return {
    json: {
      vorgangKey: base.vorgangKey,
      vorgangsnummer: base.vorgangsnummer,
      variants: [],
      kernbotschaft: fixedKernbotschaft,
      parseError: true
    }
  };
}

return {
  json: {
    vorgangKey: base.vorgangKey,
    vorgangsnummer: base.vorgangsnummer,
    variants: parsed.variants.map(clampVariant),
    kernbotschaft: fixedKernbotschaft,
    parseError: false
  }
};

