    kernbotschaft: kernbotschaft,
    kernbotschaftAnchorType: chosen ? safeStr(chosen.anchorType) : '',
    kernbotschaftAlternativen: kandidaten.filter(function(k) { return k !== chosen; }).map(function(k) { return safeStr(k && k.kernbotschaft); }),
    kernbotschaftParseError: !kernbotschaft
  })
};
